/* data+ :: content/quiz3.js — DA0-002 Domain 3 question bank (100 items). */
window.DATAPLUS = window.DATAPLUS || {}; DATAPLUS.questions = DATAPLUS.questions || [];
DATAPLUS.questions.push(
  {"id":"D3-001","domain":3,"obj":"3.1","diff":"easy","q":"An analyst must present quarterly results to the company's board of directors, none of whom have a data background. Which presentation choice BEST fits this audience?","options":["A dashboard of raw SQL query outputs","A notebook walking through each statistical model","A high-level summary with plain-language takeaways and a few clear visuals","A spreadsheet of every transaction record"],"answer":2,"explain":"<strong>A high-level summary with plain-language takeaways and a few clear visuals</strong> matches a non-technical executive audience that needs decisions, not methodology.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A dashboard of raw SQL query outputs</b>: raw query output is unreadable to non-technical leaders and exposes implementation detail they do not need.</span><span class='qd'><b>A notebook walking through each statistical model</b>: model walkthroughs are appropriate for peers, not for a board seeking business takeaways.</span><span class='qd'><b>A spreadsheet of every transaction record</b>: row-level data overwhelms executives and hides the insight behind volume.</span>"},
  {"id":"D3-002","domain":3,"obj":"3.1","diff":"medium","q":"A data team is sharing a report with an external regulatory agency rather than internal staff. Compared to an internal report, what is the MOST important additional consideration?","options":["Using more internal jargon to be precise","Increasing the number of decimal places shown","Embedding live links to internal databases","Removing or masking sensitive internal identifiers and adding context the outside reader lacks"],"answer":3,"explain":"<strong>Removing or masking sensitive internal identifiers and adding context the outside reader lacks</strong> is critical because external audiences lack internal context and must not receive confidential internal data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Using more internal jargon to be precise</b>: external readers do not share internal vocabulary, so jargon reduces clarity.</span><span class='qd'><b>Increasing the number of decimal places shown</b>: more precision does not address the audience or sensitivity concerns that matter for external delivery.</span><span class='qd'><b>Embedding live links to internal databases</b>: exposing internal database links to an outside party is a security risk and would not function for them.</span>"},
  {"id":"D3-003","domain":3,"obj":"3.1","diff":"medium","q":"An analyst is preparing the same findings for two groups: the engineering team that built the data pipeline and the marketing managers who will act on results. What is the BEST approach?","options":["Send both groups the identical detailed technical deck","Tailor the level of detail to each persona, giving engineers methodology and managers actionable insights","Send marketing the raw data and engineers the summary","Only present to one group to avoid inconsistency"],"answer":1,"explain":"<strong>Tailor the level of detail to each persona, giving engineers methodology and managers actionable insights</strong> recognizes that different personas need different levels of detail.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Send both groups the identical detailed technical deck</b>: a single technical deck overwhelms managers and ignores persona-specific needs.</span><span class='qd'><b>Send marketing the raw data and engineers the summary</b>: this reverses the appropriate detail level for each audience.</span><span class='qd'><b>Only present to one group to avoid inconsistency</b>: both stakeholders need the findings; omitting one is not a communication strategy.</span>"},
  {"id":"D3-004","domain":3,"obj":"3.1","diff":"easy","q":"Which item is an example of sensitive information that should be masked or omitted before sharing a report broadly?","options":["Customer Social Security numbers","Aggregate monthly revenue totals","The chart's color palette","The report's publication date"],"answer":0,"explain":"<strong>Customer Social Security numbers</strong> are personally identifiable, sensitive data that must be masked or removed before broad sharing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Aggregate monthly revenue totals</b>: aggregated totals usually carry low sensitivity and are commonly shared with stakeholders.</span><span class='qd'><b>The chart's color palette</b>: visual styling is presentation, not sensitive information.</span><span class='qd'><b>The report's publication date</b>: a date carries no personal or confidential risk.</span>"},
  {"id":"D3-005","domain":3,"obj":"3.1","diff":"medium","q":"A retail company wants a single number on its executive dashboard that signals whether the business is meeting its strategic sales goal. What is this metric called?","options":["A primary key","A foreign key","A key performance indicator (KPI)","A pivot field"],"answer":2,"explain":"<strong>A key performance indicator (KPI)</strong> is a measurable value that shows how well an organization is meeting a strategic objective such as a sales goal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A primary key</b>: a primary key uniquely identifies rows in a table and is not a business performance metric.</span><span class='qd'><b>A foreign key</b>: a foreign key links tables together and has no role as a strategic measure.</span><span class='qd'><b>A pivot field</b>: a pivot field is a layout choice in a pivot table, not a strategic indicator.</span>"},
  {"id":"D3-006","domain":3,"obj":"3.1","diff":"medium","q":"Before building a final dashboard, an analyst creates a low-fidelity sketch showing where each chart, filter, and KPI will go so stakeholders can give feedback early. This deliverable is BEST described as a:","options":["Data dictionary","Stored procedure","Confidence interval","Mock-up (wireframe)"],"answer":3,"explain":"<strong>Mock-up (wireframe)</strong> is a preliminary layout sketch used to gather feedback before development, reducing rework.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data dictionary</b>: a data dictionary documents field definitions, not visual layout.</span><span class='qd'><b>Stored procedure</b>: a stored procedure is reusable SQL code, unrelated to layout previews.</span><span class='qd'><b>Confidence interval</b>: a confidence interval is a statistical range estimate, not a design artifact.</span>"},
  {"id":"D3-007","domain":3,"obj":"3.1","diff":"hard","q":"An analyst designs a dashboard that conveys status using only red and green colors. A stakeholder notes some users are colorblind. Which accessibility fix BEST addresses this?","options":["Increase the saturation of the red and green","Make the dashboard load faster","Add icons or text labels in addition to color so status is not conveyed by color alone","Switch from a bar chart to a pie chart"],"answer":2,"explain":"<strong>Add icons or text labels in addition to color so status is not conveyed by color alone</strong> ensures information is perceivable by colorblind users, a core accessibility principle.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increase the saturation of the red and green</b>: more saturation still relies on color discrimination that colorblind users may lack.</span><span class='qd'><b>Make the dashboard load faster</b>: load time is a performance issue, not an accessibility fix for color perception.</span><span class='qd'><b>Switch from a bar chart to a pie chart</b>: changing chart type does not solve color-only encoding of status.</span>"},
  {"id":"D3-008","domain":3,"obj":"3.1","diff":"hard","q":"A presentation will be delivered as a recorded video to a global audience that includes deaf and hard-of-hearing viewers. Which accessibility accommodation is MOST appropriate?","options":["Use a larger font for the title slide","Increase the video resolution to 4K","Add captions and a transcript for the audio narration","Add background music"],"answer":2,"explain":"<strong>Add captions and a transcript for the audio narration</strong> provides an auditory-accessibility accommodation so deaf and hard-of-hearing viewers can follow the content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use a larger font for the title slide</b>: larger fonts help low-vision users but do nothing for those who cannot hear the narration.</span><span class='qd'><b>Increase the video resolution to 4K</b>: higher resolution does not make audio content accessible.</span><span class='qd'><b>Add background music</b>: music adds audio that captions must still convey and does not aid hearing-impaired viewers.</span>"},
  {"id":"D3-009","domain":3,"obj":"3.1","diff":"easy","q":"When communicating with a non-technical audience, which practice BEST improves understanding?","options":["Translating technical terms into plain business language","Including every formula used in the analysis","Showing the SQL behind each number","Listing all the data sources by table name"],"answer":0,"explain":"<strong>Translating technical terms into plain business language</strong> lowers the barrier for non-technical readers and keeps focus on the insight.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Including every formula used in the analysis</b>: formulas distract non-technical readers who care about conclusions.</span><span class='qd'><b>Showing the SQL behind each number</b>: SQL is meaningful to engineers, not to a non-technical audience.</span><span class='qd'><b>Listing all the data sources by table name</b>: table names are implementation detail that adds no value for business readers.</span>"},
  {"id":"D3-010","domain":3,"obj":"3.1","diff":"medium","q":"A C-suite executive asks for a report, while a frontline individual contributor (IC) analyst asks about the same topic. How should the level of detail differ?","options":["The C-suite report should be higher-level and summarized while the IC gets granular detail","The C-suite report should be more granular than the IC's","Both should receive the same granularity","Neither needs any visuals"],"answer":0,"explain":"<strong>The C-suite report should be higher-level and summarized while the IC gets granular detail</strong> aligns detail with role: executives need the big picture, ICs need operational specifics.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The C-suite report should be more granular than the IC's</b>: this inverts the appropriate level of detail for each role.</span><span class='qd'><b>Both should receive the same granularity</b>: one-size-fits-all ignores differing decision needs.</span><span class='qd'><b>Neither needs any visuals</b>: visuals aid both audiences; the claim is simply false.</span>"},
  {"id":"D3-011","domain":3,"obj":"3.1","diff":"medium","q":"An analyst is unsure whether a customer churn report can be emailed to a partner company. What should be confirmed FIRST regarding the data?","options":["Whether the chart colors match the partner's branding","Whether the font is large enough","Whether the data contains sensitive or confidential information that restricts external sharing","Whether the file is saved as PDF"],"answer":2,"explain":"<strong>Whether the data contains sensitive or confidential information that restricts external sharing</strong> must be verified first because sharing sensitive data externally can violate policy or law.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Whether the chart colors match the partner's branding</b>: branding is cosmetic and secondary to data sensitivity.</span><span class='qd'><b>Whether the font is large enough</b>: legibility matters but does not determine whether sharing is permitted.</span><span class='qd'><b>Whether the file is saved as PDF</b>: file format does not address the legality or policy of sharing the content.</span>"},
  {"id":"D3-012","domain":3,"obj":"3.1","diff":"hard","q":"A product team and a finance team both consume the same revenue dashboard but ask different questions of it. The BEST way to serve both personas in one dashboard is to:","options":["Provide interactive filters and drill-downs so each persona can reach the detail it needs","Hard-code a single fixed view for the product team only","Remove all charts and show only a table","Build it in raw HTML with no interactivity"],"answer":0,"explain":"<strong>Provide interactive filters and drill-downs so each persona can reach the detail it needs</strong> lets distinct personas self-serve different levels of detail from one artifact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hard-code a single fixed view for the product team only</b>: a fixed single-persona view fails the finance team's needs.</span><span class='qd'><b>Remove all charts and show only a table</b>: stripping visuals reduces clarity without serving either persona better.</span><span class='qd'><b>Build it in raw HTML with no interactivity</b>: removing interactivity prevents each persona from reaching its needed detail.</span>"},
  {"id":"D3-013","domain":3,"obj":"3.1","diff":"easy","q":"Which audience is considered 'external' for the purposes of choosing a communication approach?","options":["A vendor or customer outside the organization","The analyst's direct manager","A teammate on the same data squad","The internal IT help desk"],"answer":0,"explain":"<strong>A vendor or customer outside the organization</strong> is an external audience, which changes sensitivity and context requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The analyst's direct manager</b>: a manager is an internal stakeholder.</span><span class='qd'><b>A teammate on the same data squad</b>: a teammate is clearly internal.</span><span class='qd'><b>The internal IT help desk</b>: the help desk is part of the same organization and is internal.</span>"},
  {"id":"D3-014","domain":3,"obj":"3.1","diff":"medium","q":"A stakeholder reviews an analyst's dashboard mock-up and requests moving a KPI to the top and removing a confusing chart. What is the PRIMARY benefit of catching this at the mock-up stage?","options":["It makes the final SQL run faster","It guarantees the statistics are correct","It encrypts the underlying data","It allows changes before costly development, reducing rework"],"answer":3,"explain":"<strong>It allows changes before costly development, reducing rework</strong> is the core value of mock-ups: feedback is cheap to incorporate before the artifact is built.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the final SQL run faster</b>: layout feedback has no effect on query performance.</span><span class='qd'><b>It guarantees the statistics are correct</b>: a mock-up shows layout, not statistical accuracy.</span><span class='qd'><b>It encrypts the underlying data</b>: mock-ups do not provide any data security function.</span>"},
  {"id":"D3-015","domain":3,"obj":"3.1","diff":"hard","q":"An analyst must present a complex methodology to a mixed audience of technical peers and non-technical executives in the same meeting. What is the BEST structuring approach?","options":["Lead with the high-level insight for executives, then offer a technical appendix or deep-dive for peers","Lead with the technical derivation and skip the summary","Present only the technical detail since peers are present","Cancel the meeting and email a spreadsheet"],"answer":0,"explain":"<strong>Lead with the high-level insight for executives, then offer a technical appendix or deep-dive for peers</strong> serves both detail levels without losing either audience.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Lead with the technical derivation and skip the summary</b>: opening with derivation loses executives immediately.</span><span class='qd'><b>Present only the technical detail since peers are present</b>: ignoring executives fails half the audience.</span><span class='qd'><b>Cancel the meeting and email a spreadsheet</b>: avoiding the presentation does not communicate the methodology to either group.</span>"},
  {"id":"D3-016","domain":3,"obj":"3.1","diff":"medium","q":"A healthcare analyst plans to share a patient-outcomes report with the hospital's marketing department. Which step is MOST important before sharing?","options":["Add a company logo to each slide","De-identify or aggregate any protected health information so individuals cannot be identified","Convert the charts to 3D","Choose a sans-serif font"],"answer":1,"explain":"<strong>De-identify or aggregate any protected health information so individuals cannot be identified</strong> protects sensitive PHI before it reaches an audience without a clinical need.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add a company logo to each slide</b>: branding is cosmetic and ignores the sensitivity risk.</span><span class='qd'><b>Convert the charts to 3D</b>: 3D styling can reduce clarity and does nothing for data protection.</span><span class='qd'><b>Choose a sans-serif font</b>: font choice is irrelevant to protecting PHI.</span>"},
  {"id":"D3-017","domain":3,"obj":"3.1","diff":"easy","q":"What is the MAIN goal of accessibility considerations in data communication?","options":["To make reports load faster on servers","To reduce the number of charts","To increase the data warehouse size","To ensure people with disabilities can perceive and understand the information"],"answer":3,"explain":"<strong>To ensure people with disabilities can perceive and understand the information</strong> is the purpose of accessibility, covering visual and auditory needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make reports load faster on servers</b>: speed is a performance goal, not accessibility.</span><span class='qd'><b>To reduce the number of charts</b>: chart count is unrelated to accessibility.</span><span class='qd'><b>To increase the data warehouse size</b>: storage capacity has nothing to do with accessibility.</span>"},
  {"id":"D3-018","domain":3,"obj":"3.1","diff":"medium","q":"An operations manager wants a weekly report focused on a few numbers that track whether the team is hitting its targets. Which content best serves this need?","options":["A narrative essay on data history","Every raw record from the source system","A list of all database tables used","A concise set of relevant KPIs with trend indicators"],"answer":3,"explain":"<strong>A concise set of relevant KPIs with trend indicators</strong> gives the manager target-tracking metrics in a digestible form.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A narrative essay on data history</b>: a long essay buries the few numbers the manager needs.</span><span class='qd'><b>Every raw record from the source system</b>: row-level data does not track targets at a glance.</span><span class='qd'><b>A list of all database tables used</b>: table inventories are implementation detail, not performance tracking.</span>"},
  {"id":"D3-019","domain":3,"obj":"3.1","diff":"hard","q":"During discovery, an analyst documents who will use a report, what decisions they make, and how technical they are. This profiling activity produces what artifact that guides the communication approach?","options":["A primary key","A regression line","A union query","A user persona"],"answer":3,"explain":"<strong>A user persona</strong> captures the audience's role, needs, and technical level, directly informing how to communicate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A primary key</b>: a primary key is a database identifier, not an audience profile.</span><span class='qd'><b>A regression line</b>: a regression line is a statistical model element, unrelated to audience profiling.</span><span class='qd'><b>A union query</b>: a union query combines result sets and has nothing to do with audience analysis.</span>"},
  {"id":"D3-020","domain":3,"obj":"3.1","diff":"medium","q":"A technical audience of data engineers reviews an analysis. Compared to a non-technical audience, what can the analyst appropriately include?","options":["Less detail and no methodology","Methodology, assumptions, and details such as query logic and model parameters","Only a single headline number","No charts at all"],"answer":1,"explain":"<strong>Methodology, assumptions, and details such as query logic and model parameters</strong> is appropriate for a technical audience that can interpret and scrutinize the work.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Less detail and no methodology</b>: technical peers expect and benefit from methodology, so withholding it is wrong.</span><span class='qd'><b>Only a single headline number</b>: a lone number underserves an audience capable of deeper review.</span><span class='qd'><b>No charts at all</b>: visuals still help engineers; removing them is unnecessary.</span>"},
  {"id":"D3-021","domain":3,"obj":"3.1","diff":"easy","q":"Which of the following is the BEST description of a high level of detail in a report?","options":["A single executive headline metric","A logo and color scheme","Granular, row-level breakdowns and underlying calculations","A one-sentence summary"],"answer":2,"explain":"<strong>Granular, row-level breakdowns and underlying calculations</strong> represents a high level of detail suited to analysts who need to dig in.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single executive headline metric</b>: one metric is a low level of detail.</span><span class='qd'><b>A logo and color scheme</b>: branding is styling, not a level of detail.</span><span class='qd'><b>A one-sentence summary</b>: a summary is the lowest level of detail.</span>"},
  {"id":"D3-022","domain":3,"obj":"3.1","diff":"hard","q":"An analyst must email findings that include both public summary figures and a confidential customer list. What is the BEST handling?","options":["Send everything together to save time","Post the whole file to a shared public drive","Separate the content: share public figures broadly but restrict the confidential list to authorized recipients only","Delete the public figures and send only the confidential list"],"answer":2,"explain":"<strong>Separate the content: share public figures broadly but restrict the confidential list to authorized recipients only</strong> applies appropriate handling to each sensitivity level.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Send everything together to save time</b>: bundling exposes confidential data to anyone receiving the public figures.</span><span class='qd'><b>Post the whole file to a shared public drive</b>: public posting of confidential customer data is a serious breach.</span><span class='qd'><b>Delete the public figures and send only the confidential list</b>: this needlessly removes shareable content while still risking the sensitive list.</span>"},
  {"id":"D3-023","domain":3,"obj":"3.1","diff":"medium","q":"A wireframe for a new sales dashboard is being reviewed. Which feedback is MOST appropriate to give at this stage?","options":["The exact pixel color of the third bar is slightly off","The database index is fragmented","The KPI placement and overall layout do not match how users scan the page","The ETL job ran two minutes late"],"answer":2,"explain":"<strong>The KPI placement and overall layout do not match how users scan the page</strong> is layout feedback, exactly what a wireframe review is meant to capture.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The exact pixel color of the third bar is slightly off</b>: fine color tuning is premature for a low-fidelity wireframe.</span><span class='qd'><b>The database index is fragmented</b>: indexing is a backend performance topic, not layout feedback.</span><span class='qd'><b>The ETL job ran two minutes late</b>: pipeline timing is unrelated to reviewing a layout mock-up.</span>"},
  {"id":"D3-024","domain":3,"obj":"3.1","diff":"medium","q":"An analyst presents to investors (external) versus the internal finance team. Which difference in approach is MOST appropriate?","options":["Use identical content for both","For investors, include every internal cost spreadsheet","For the internal team, hide all the numbers","For investors, focus on outcomes and strategy and avoid internal-only operational detail"],"answer":3,"explain":"<strong>For investors, focus on outcomes and strategy and avoid internal-only operational detail</strong> respects the external audience's needs and protects internal-only information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use identical content for both</b>: internal and external audiences differ in context and sensitivity, so identical content is inappropriate.</span><span class='qd'><b>For investors, include every internal cost spreadsheet</b>: detailed internal costs may be confidential and excessive for investors.</span><span class='qd'><b>For the internal team, hide all the numbers</b>: the internal finance team needs the numbers to do their job.</span>"},
  {"id":"D3-025","domain":3,"obj":"3.1","diff":"easy","q":"Why might an analyst add alternative text (alt text) to images in a report?","options":["To make images understandable to screen-reader users who are visually impaired","To improve query performance","To compress the file size","To change the chart colors"],"answer":0,"explain":"<strong>To make images understandable to screen-reader users who are visually impaired</strong> is the purpose of alt text, a visual-accessibility accommodation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To improve query performance</b>: alt text has no effect on queries.</span><span class='qd'><b>To compress the file size</b>: alt text is metadata text and does not compress images.</span><span class='qd'><b>To change the chart colors</b>: alt text describes content; it does not alter colors.</span>"},
  {"id":"D3-026","domain":3,"obj":"3.1","diff":"hard","q":"A KPI on a dashboard is described as 'leading' rather than 'lagging.' What does choosing a leading KPI communicate to stakeholders?","options":["It is an early predictive signal that helps anticipate future performance","It reports only past results that cannot change","It is the same as a vanity metric","It requires no data to compute"],"answer":0,"explain":"<strong>It is an early predictive signal that helps anticipate future performance</strong> defines a leading KPI, which moves before the outcome it predicts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It reports only past results that cannot change</b>: that describes a lagging KPI, the opposite of leading.</span><span class='qd'><b>It is the same as a vanity metric</b>: a vanity metric looks impressive but lacks decision value, which is unrelated to the leading/lagging distinction.</span><span class='qd'><b>It requires no data to compute</b>: all KPIs require data; this is simply false.</span>"},
  {"id":"D3-027","domain":3,"obj":"3.1","diff":"medium","q":"An analyst is told the audience for a report is 'non-technical and external.' Which combination of choices fits BEST?","options":["Heavy jargon plus internal system names","Plain language, business-focused insights, and removal of confidential internal data","Raw SQL plus internal database links","Detailed model parameters and assumptions"],"answer":1,"explain":"<strong>Plain language, business-focused insights, and removal of confidential internal data</strong> addresses both the non-technical and external nature of the audience.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Heavy jargon plus internal system names</b>: jargon and internal names fail both the non-technical and external requirements.</span><span class='qd'><b>Raw SQL plus internal database links</b>: SQL and internal links suit neither a non-technical nor an external reader.</span><span class='qd'><b>Detailed model parameters and assumptions</b>: deep methodology overwhelms a non-technical audience.</span>"},
  {"id":"D3-028","domain":3,"obj":"3.1","diff":"medium","q":"A dashboard intended for the CEO contains 18 charts and dozens of metrics. The CEO says it is overwhelming. What is the BEST revision?","options":["Add more charts to provide context","Reduce to a small number of the most decision-relevant KPIs with clear visuals","Switch every chart to a table","Increase the number of metrics per chart"],"answer":1,"explain":"<strong>Reduce to a small number of the most decision-relevant KPIs with clear visuals</strong> matches the executive's need for a focused, high-level view.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add more charts to provide context</b>: more charts worsen the overload.</span><span class='qd'><b>Switch every chart to a table</b>: tables of many numbers are even harder to scan quickly.</span><span class='qd'><b>Increase the number of metrics per chart</b>: cramming metrics increases clutter rather than reducing it.</span>"},
  {"id":"D3-029","domain":3,"obj":"3.1","diff":"hard","q":"An analyst wants the report to remain usable by a user who navigates only with a keyboard and uses high-contrast mode. Which design decision BEST supports this?","options":["Ensure interactive elements are keyboard-focusable and text meets contrast guidelines","Convey meaning only through hover tooltips that require a mouse","Use light gray text on a white background for a clean look","Embed information solely in images without text equivalents"],"answer":0,"explain":"<strong>Ensure interactive elements are keyboard-focusable and text meets contrast guidelines</strong> directly supports keyboard navigation and high-contrast needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Convey meaning only through hover tooltips that require a mouse</b>: mouse-only tooltips exclude keyboard users.</span><span class='qd'><b>Use light gray text on a white background for a clean look</b>: low contrast fails high-contrast and low-vision users.</span><span class='qd'><b>Embed information solely in images without text equivalents</b>: image-only content is invisible to screen readers.</span>"},
  {"id":"D3-030","domain":3,"obj":"3.1","diff":"easy","q":"Which statement BEST captures why an analyst profiles the audience before choosing a communication approach?","options":["So the file format is always PDF","Because audience profiling encrypts the data","Because the right level of detail, language, and visuals depend on who will consume the information","Because it speeds up the database"],"answer":2,"explain":"<strong>Because the right level of detail, language, and visuals depend on who will consume the information</strong> is the central reason to profile the audience first.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>So the file format is always PDF</b>: file format is not the driver of audience analysis.</span><span class='qd'><b>Because audience profiling encrypts the data</b>: profiling has no encryption function.</span><span class='qd'><b>Because it speeds up the database</b>: audience analysis has no effect on database performance.</span>"},
  {"id":"D3-031","domain":3,"obj":"3.1","diff":"medium","q":"A monthly report must show whether customer satisfaction is improving toward a strategic goal of 90%. Which element MOST directly communicates progress toward that goal?","options":["A raw export of every survey response","A list of survey question IDs","The database connection string","A KPI showing current satisfaction against the 90% target with a trend arrow"],"answer":3,"explain":"<strong>A KPI showing current satisfaction against the 90% target with a trend arrow</strong> communicates progress toward the strategic goal at a glance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A raw export of every survey response</b>: raw responses do not show progress toward a target.</span><span class='qd'><b>A list of survey question IDs</b>: question IDs are metadata, not progress indicators.</span><span class='qd'><b>The database connection string</b>: a connection string is technical plumbing, irrelevant to goal tracking.</span>"},
  {"id":"D3-032","domain":3,"obj":"3.1","diff":"medium","q":"An external auditor requests data, but some fields are sensitive while others are not. What is the BEST communication approach?","options":["Provide all fields unredacted for completeness","Provide only the non-sensitive fields the auditor needs and mask or withhold the sensitive ones per policy","Refuse to share anything","Share sensitive fields but rename the columns"],"answer":1,"explain":"<strong>Provide only the non-sensitive fields the auditor needs and mask or withhold the sensitive ones per policy</strong> balances cooperation with protecting sensitive data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Provide all fields unredacted for completeness</b>: oversharing sensitive data to an external party violates protection requirements.</span><span class='qd'><b>Refuse to share anything</b>: refusing blocks a legitimate audit; the non-sensitive data can be shared.</span><span class='qd'><b>Share sensitive fields but rename the columns</b>: renaming columns does not protect the underlying sensitive values.</span>"},
  {"id":"D3-033","domain":3,"obj":"3.1","diff":"hard","q":"A team debates whether to deliver insights as a live interactive dashboard or a static narrative summary. The audience is busy executives who want a clear story and one recommendation. Which is the BETTER fit and why?","options":["A live interactive dashboard, because executives enjoy exploring filters","Neither; send the raw data","A static summary, because dashboards cannot show numbers","A static narrative summary, because it delivers a focused story and recommendation without requiring exploration"],"answer":3,"explain":"<strong>A static narrative summary, because it delivers a focused story and recommendation without requiring exploration</strong> matches busy executives who want conclusions, not analysis tools.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A live interactive dashboard, because executives enjoy exploring filters</b>: busy executives typically want the answer, not exploration work.</span><span class='qd'><b>Neither; send the raw data</b>: raw data forces executives to do the analysis themselves.</span><span class='qd'><b>A static summary, because dashboards cannot show numbers</b>: dashboards do show numbers, so the stated reason is false.</span>"},
  {"id":"D3-034","domain":3,"obj":"3.2","diff":"easy","q":"An analyst calculates the average daily sales by summing all daily totals and dividing by the number of days. Which measure of central tendency is this?","options":["Median","Mode","Mean","Range"],"answer":2,"explain":"<strong>Mean</strong> is the arithmetic average: the sum of values divided by the count of values.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Median</b>: the median is the middle value when data is ordered, not the sum divided by count.</span><span class='qd'><b>Mode</b>: the mode is the most frequently occurring value, not an average.</span><span class='qd'><b>Range</b>: the range is the difference between the maximum and minimum, a measure of spread, not center.</span>"},
  {"id":"D3-035","domain":3,"obj":"3.2","diff":"medium","q":"A dataset of home prices contains a few extremely expensive mansions that pull the average far above what a typical home costs. Which measure of central tendency BEST represents the typical home price?","options":["Mean","Median","Mode","Standard deviation"],"answer":1,"explain":"<strong>Median</strong> is resistant to extreme outliers, so it better represents the typical value in a right-skewed price distribution.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mean</b>: the mean is pulled upward by the high-priced mansions, overstating the typical price.</span><span class='qd'><b>Mode</b>: the mode is the most common price, which may not reflect the center of a continuous price distribution.</span><span class='qd'><b>Standard deviation</b>: standard deviation measures spread, not the typical central value.</span>"},
  {"id":"D3-036","domain":3,"obj":"3.2","diff":"easy","q":"A survey asks respondents to pick a favorite color and the analyst wants the single most common response. Which measure should be used?","options":["Mean","Median","Variance","Mode"],"answer":3,"explain":"<strong>Mode</strong> identifies the most frequently occurring category, which is the only valid central measure for nominal data like color.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mean</b>: you cannot average categorical color values.</span><span class='qd'><b>Median</b>: a median requires ordered data, but colors have no inherent order.</span><span class='qd'><b>Variance</b>: variance measures numeric spread and is undefined for unordered categories.</span>"},
  {"id":"D3-037","domain":3,"obj":"3.2","diff":"medium","q":"An analyst reports that daily order counts range from 40 to 220. What statistical measure has been described?","options":["The mean","The mode","The range","The correlation"],"answer":2,"explain":"<strong>The range</strong> is the difference between the maximum and minimum values, here described by stating the 40-to-220 span.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The mean</b>: the mean is an average, not the spread between extremes.</span><span class='qd'><b>The mode</b>: the mode is the most frequent value, not the min-to-max span.</span><span class='qd'><b>The correlation</b>: correlation measures the relationship between two variables, not the spread of one.</span>"},
  {"id":"D3-038","domain":3,"obj":"3.2","diff":"hard","q":"Two products both average 50 units sold per day, but Product A's daily sales vary widely while Product B's are very consistent. Which statistic BEST captures this difference?","options":["The mean","The standard deviation","The mode","The median"],"answer":1,"explain":"<strong>The standard deviation</strong> quantifies how much values deviate from the mean, so a larger value reflects Product A's wider variability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The mean</b>: both products share the same mean, so it cannot distinguish them.</span><span class='qd'><b>The mode</b>: the mode reflects the most common value, not the spread.</span><span class='qd'><b>The median</b>: the median describes the center, not how dispersed the values are.</span>"},
  {"id":"D3-039","domain":3,"obj":"3.2","diff":"medium","q":"An analyst wants to know, on average, how far each data point lies from the mean, expressed in the original units of the data. Which measure should be reported?","options":["Standard deviation","Variance","Range","Mode"],"answer":0,"explain":"<strong>Standard deviation</strong> is the square root of variance and is expressed in the same units as the data, describing average distance from the mean.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Variance</b>: variance is in squared units, not the original units requested.</span><span class='qd'><b>Range</b>: range only uses the two extreme values, not the typical distance from the mean.</span><span class='qd'><b>Mode</b>: the mode is a central-tendency measure, not a measure of dispersion.</span>"},
  {"id":"D3-040","domain":3,"obj":"3.2","diff":"hard","q":"A student scored 85 on an exam where the mean was 70 and the standard deviation was 5. What is the student's z-score, and what does it mean?","options":["z = -3, the score is below the mean","z = 3, the score is 3 standard deviations above the mean","z = 0.2, the score is near the mean","z = 15, the score is 15 points above the mean"],"answer":1,"explain":"<strong>z = 3, the score is 3 standard deviations above the mean</strong> because z = (85 - 70) / 5 = 15 / 5 = 3, indicating an unusually high score.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>z = -3, the score is below the mean</b>: the score is above the mean, so the z-score is positive.</span><span class='qd'><b>z = 0.2, the score is near the mean</b>: 0.2 ignores dividing the 15-point gap by the standard deviation of 5.</span><span class='qd'><b>z = 15, the score is 15 points above the mean</b>: 15 is the raw difference, not the standardized z-score.</span>"},
  {"id":"D3-041","domain":3,"obj":"3.2","diff":"medium","q":"An analyst summarizes a completed dataset with averages, counts, and percentages to describe what has already happened. Which type of analysis is this?","options":["Descriptive analysis","Predictive analysis","Prescriptive analysis","Inferential analysis"],"answer":0,"explain":"<strong>Descriptive analysis</strong> summarizes historical data to describe what has happened using measures like averages and counts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Predictive analysis</b>: prediction forecasts future outcomes rather than describing the past.</span><span class='qd'><b>Prescriptive analysis</b>: prescription recommends actions, going beyond describing what happened.</span><span class='qd'><b>Inferential analysis</b>: inference generalizes from a sample to a population, not merely describing the data at hand.</span>"},
  {"id":"D3-042","domain":3,"obj":"3.2","diff":"medium","q":"A company uses last year's sales trends and a regression model to forecast next quarter's revenue. Which analysis category does this represent?","options":["Descriptive","Diagnostic","Prescriptive","Predictive"],"answer":3,"explain":"<strong>Predictive</strong> analysis uses historical data and models such as regression to forecast likely future outcomes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Descriptive</b>: descriptive analysis explains past data, it does not forecast the future.</span><span class='qd'><b>Diagnostic</b>: diagnostic analysis explains why something happened, not what will happen.</span><span class='qd'><b>Prescriptive</b>: prescriptive analysis recommends the best action, which is a step beyond forecasting.</span>"},
  {"id":"D3-043","domain":3,"obj":"3.2","diff":"hard","q":"An optimization engine evaluates forecasts and recommends the specific staffing levels that will minimize wait times next week. Which analysis category BEST describes this?","options":["Prescriptive","Descriptive","Predictive","Exploratory"],"answer":0,"explain":"<strong>Prescriptive</strong> analysis goes beyond forecasting to recommend the best course of action, such as optimal staffing levels.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Descriptive</b>: descriptive analysis only summarizes past data.</span><span class='qd'><b>Predictive</b>: predictive analysis forecasts outcomes but stops short of recommending the action to take.</span><span class='qd'><b>Exploratory</b>: exploratory analysis investigates patterns without prescribing a specific decision.</span>"},
  {"id":"D3-044","domain":3,"obj":"3.2","diff":"medium","q":"Before formal modeling, an analyst makes scatter plots and histograms to understand distributions, spot outliers, and form hypotheses. This activity is BEST described as:","options":["Exploratory data analysis (EDA)","Prescriptive analytics","Hypothesis confirmation","Data destruction"],"answer":0,"explain":"<strong>Exploratory data analysis (EDA)</strong> uses visual and summary techniques to understand data, find anomalies, and generate hypotheses before formal modeling.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Prescriptive analytics</b>: prescriptive work recommends actions, which is the opposite end of the analytics process.</span><span class='qd'><b>Hypothesis confirmation</b>: EDA generates hypotheses; confirmation comes later with formal testing.</span><span class='qd'><b>Data destruction</b>: data destruction is a governance disposal activity, unrelated to analysis.</span>"},
  {"id":"D3-045","domain":3,"obj":"3.2","diff":"hard","q":"An analyst wants to test whether the mean conversion rate of two different landing-page designs is significantly different. The samples are small and means are being compared. Which test is MOST appropriate?","options":["Chi-square test","Correlation coefficient","t-test","Mode calculation"],"answer":2,"explain":"<strong>t-test</strong> compares the means of two groups and is appropriate for small samples to assess whether the difference is statistically significant.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Chi-square test</b>: chi-square tests associations between categorical variables, not differences between two means.</span><span class='qd'><b>Correlation coefficient</b>: correlation measures the strength of a linear relationship, not a difference in means.</span><span class='qd'><b>Mode calculation</b>: the mode is a descriptive statistic and tests nothing for significance.</span>"},
  {"id":"D3-046","domain":3,"obj":"3.2","diff":"hard","q":"An analyst wants to determine whether there is an association between two categorical variables: region (North/South) and whether customers churned (yes/no). Which statistical test fits BEST?","options":["Chi-square test","t-test","Linear regression","Z-score"],"answer":0,"explain":"<strong>Chi-square test</strong> evaluates whether two categorical variables are independent or associated, which fits region versus churn.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>t-test</b>: a t-test compares means of continuous data, not associations between categories.</span><span class='qd'><b>Linear regression</b>: regression models a continuous outcome from predictors, not a category-to-category association test.</span><span class='qd'><b>Z-score</b>: a z-score standardizes a single value and does not test association.</span>"},
  {"id":"D3-047","domain":3,"obj":"3.2","diff":"hard","q":"A hypothesis test returns a p-value of 0.03 with a significance level (alpha) of 0.05. What is the correct interpretation?","options":["The result is statistically significant; reject the null hypothesis","The result is not significant; fail to reject the null hypothesis","The null hypothesis is proven true","There is a 3% chance the alternative hypothesis is false"],"answer":0,"explain":"<strong>The result is statistically significant; reject the null hypothesis</strong> because the p-value (0.03) is below alpha (0.05), indicating the observed result is unlikely under the null.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The result is not significant; fail to reject the null hypothesis</b>: p < alpha means the result IS significant, so this is backwards.</span><span class='qd'><b>The null hypothesis is proven true</b>: statistical tests never prove a hypothesis true; they only reject or fail to reject.</span><span class='qd'><b>There is a 3% chance the alternative hypothesis is false</b>: the p-value is the probability of the data under the null, not the probability the alternative is false.</span>"},
  {"id":"D3-048","domain":3,"obj":"3.2","diff":"medium","q":"An analyst reports a 95% confidence interval for average order value of $48 to $52. What does this MOST accurately convey?","options":["95% of all orders fall between $48 and $52","If the sampling were repeated many times, about 95% of such intervals would contain the true mean","The true mean is exactly $50","Exactly 95 orders were between $48 and $52"],"answer":1,"explain":"<strong>If the sampling were repeated many times, about 95% of such intervals would contain the true mean</strong> is the correct interpretation of a 95% confidence interval.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>95% of all orders fall between $48 and $52</b>: the interval estimates the mean, not the spread of individual orders.</span><span class='qd'><b>The true mean is exactly $50</b>: the interval gives a range of plausible values, not a single exact mean.</span><span class='qd'><b>Exactly 95 orders were between $48 and $52</b>: the 95% refers to confidence level, not a count of orders.</span>"},
  {"id":"D3-049","domain":3,"obj":"3.2","diff":"medium","q":"An analyst computes a correlation coefficient of -0.85 between hours of TV watched and exam scores. What does this indicate?","options":["A strong negative relationship","A strong positive relationship","No relationship","A causal relationship proving TV lowers scores"],"answer":0,"explain":"<strong>A strong negative relationship</strong> is indicated by a correlation near -1, meaning as one variable rises the other tends to fall.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A strong positive relationship</b>: a positive relationship would yield a coefficient near +1, not -0.85.</span><span class='qd'><b>No relationship</b>: no relationship corresponds to a coefficient near 0, not -0.85.</span><span class='qd'><b>A causal relationship proving TV lowers scores</b>: correlation does not prove causation.</span>"},
  {"id":"D3-050","domain":3,"obj":"3.2","diff":"hard","q":"An analyst fits a linear regression of monthly sales on advertising spend and gets the equation sales = 5000 + 3.2 * spend. How should the coefficient 3.2 be interpreted?","options":["Total sales are 3.2 units","Sales are 3.2% of spend","For each additional dollar of ad spend, sales increase by about 3.2 units on average","The intercept is 3.2"],"answer":2,"explain":"<strong>For each additional dollar of ad spend, sales increase by about 3.2 units on average</strong> is the meaning of the slope coefficient in a regression line.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Total sales are 3.2 units</b>: 3.2 is a rate of change, not a total.</span><span class='qd'><b>Sales are 3.2% of spend</b>: the coefficient is units per dollar, not a percentage.</span><span class='qd'><b>The intercept is 3.2</b>: the intercept is 5000; 3.2 is the slope.</span>"},
  {"id":"D3-051","domain":3,"obj":"3.2","diff":"medium","q":"A retailer wants to identify which customers will likely respond to a promotion using a model trained on past campaigns. Which combination of analysis type and technique fits BEST?","options":["Predictive analysis using regression or classification","Descriptive analysis using a pie chart","Prescriptive analysis using a data dictionary","Descriptive analysis using the mode"],"answer":0,"explain":"<strong>Predictive analysis using regression or classification</strong> uses historical campaign data to predict future customer response.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Descriptive analysis using a pie chart</b>: a pie chart describes the past, it does not predict future response.</span><span class='qd'><b>Prescriptive analysis using a data dictionary</b>: a data dictionary documents fields and does not predict behavior.</span><span class='qd'><b>Descriptive analysis using the mode</b>: the mode summarizes a current distribution, not future likelihood.</span>"},
  {"id":"D3-052","domain":3,"obj":"3.2","diff":"easy","q":"In a spreadsheet, an analyst needs a function that returns one value if a condition is true and another if it is false. Which category of function is this?","options":["A date function","A string function","A math function","A logical function (such as IF)"],"answer":3,"explain":"<strong>A logical function (such as IF)</strong> evaluates a condition and returns different results based on whether it is true or false.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A date function</b>: date functions manipulate dates and times, not conditional logic.</span><span class='qd'><b>A string function</b>: string functions operate on text, not boolean conditions.</span><span class='qd'><b>A math function</b>: math functions perform arithmetic, not conditional branching.</span>"},
  {"id":"D3-053","domain":3,"obj":"3.2","diff":"medium","q":"An analyst needs to extract the first three characters from each product code stored as text. Which function category is appropriate?","options":["Logical functions","String functions (such as LEFT or SUBSTRING)","Date functions","Aggregate functions"],"answer":1,"explain":"<strong>String functions (such as LEFT or SUBSTRING)</strong> manipulate text values, including extracting a portion of a string.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Logical functions</b>: logical functions evaluate true/false conditions, not text extraction.</span><span class='qd'><b>Date functions</b>: date functions work on temporal values, not characters in a code.</span><span class='qd'><b>Aggregate functions</b>: aggregates summarize many rows, they do not slice individual strings.</span>"},
  {"id":"D3-054","domain":3,"obj":"3.2","diff":"medium","q":"An analyst must calculate the number of days between an order date and a ship date. Which function category should be used?","options":["String functions","Logical functions","Date functions (such as DATEDIFF)","Text concatenation"],"answer":2,"explain":"<strong>Date functions (such as DATEDIFF)</strong> compute differences and intervals between dates, like days between order and ship.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>String functions</b>: string functions process text, not date arithmetic.</span><span class='qd'><b>Logical functions</b>: logical functions return true/false, not a day count.</span><span class='qd'><b>Text concatenation</b>: concatenation joins strings and cannot compute a date interval.</span>"},
  {"id":"D3-055","domain":3,"obj":"3.2","diff":"easy","q":"Which spreadsheet function category would be used to compute the square root or round a number?","options":["String functions","Mathematical functions","Date functions","Logical functions"],"answer":1,"explain":"<strong>Mathematical functions</strong> perform numeric operations such as SQRT and ROUND.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>String functions</b>: string functions handle text, not arithmetic.</span><span class='qd'><b>Date functions</b>: date functions handle temporal values, not rounding numbers.</span><span class='qd'><b>Logical functions</b>: logical functions evaluate conditions, not numeric math.</span>"},
  {"id":"D3-056","domain":3,"obj":"3.2","diff":"hard","q":"An analyst notices the mean income in a dataset is $95,000 but the median is $52,000. What does this gap MOST likely indicate?","options":["The data is perfectly symmetric","The standard deviation is zero","The distribution is right-skewed by high-income outliers","The mode equals the mean"],"answer":2,"explain":"<strong>The distribution is right-skewed by high-income outliers</strong> because a mean well above the median signals a long right tail pulling the average up.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data is perfectly symmetric</b>: in symmetric data the mean and median are approximately equal, not far apart.</span><span class='qd'><b>The standard deviation is zero</b>: a zero standard deviation means all values are identical, which contradicts the spread implied here.</span><span class='qd'><b>The mode equals the mean</b>: nothing about the mode is established, and it would not explain the mean-median gap.</span>"},
  {"id":"D3-057","domain":3,"obj":"3.2","diff":"medium","q":"An analyst standardizes test scores so they can be compared across different exams with different scales. Which statistic accomplishes this by expressing each score in standard-deviation units from its mean?","options":["The range","The mode","The median","The z-score"],"answer":3,"explain":"<strong>The z-score</strong> standardizes a value by subtracting the mean and dividing by the standard deviation, enabling cross-scale comparison.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The range</b>: the range describes spread of one dataset and does not standardize values.</span><span class='qd'><b>The mode</b>: the mode reports the most frequent value, not a standardized position.</span><span class='qd'><b>The median</b>: the median is a central value and does not express distance in standard-deviation units.</span>"},
  {"id":"D3-058","domain":3,"obj":"3.2","diff":"hard","q":"An analyst runs a study and obtains a p-value of 0.20 with alpha set at 0.05. What is the correct conclusion?","options":["Reject the null hypothesis; the effect is significant","The null hypothesis is definitely true","The sample must be discarded","Fail to reject the null hypothesis; there is insufficient evidence of an effect"],"answer":3,"explain":"<strong>Fail to reject the null hypothesis; there is insufficient evidence of an effect</strong> because p (0.20) exceeds alpha (0.05).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reject the null hypothesis; the effect is significant</b>: rejection requires p below alpha, which is not the case here.</span><span class='qd'><b>The null hypothesis is definitely true</b>: failing to reject is not proof the null is true.</span><span class='qd'><b>The sample must be discarded</b>: a non-significant result does not mean the data is invalid.</span>"},
  {"id":"D3-059","domain":3,"obj":"3.2","diff":"medium","q":"An analyst examines whether monthly revenue has been steadily increasing over the past three years. Which analytical approach fits BEST?","options":["Mode of the categorical labels","Chi-square test of independence","Computing a single z-score","Trend analysis over the time series"],"answer":3,"explain":"<strong>Trend analysis over the time series</strong> examines how a metric changes over time, ideal for detecting steady increases.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mode of the categorical labels</b>: the mode summarizes frequency of categories, not a temporal trend.</span><span class='qd'><b>Chi-square test of independence</b>: chi-square tests categorical association, not a trend over time.</span><span class='qd'><b>Computing a single z-score</b>: a z-score standardizes one value, revealing no trend.</span>"},
  {"id":"D3-060","domain":3,"obj":"3.2","diff":"hard","q":"A manager wants to know not just what is likely to happen but the best decision to make to achieve the most profitable outcome. Which analytics maturity level does this require?","options":["Descriptive","Diagnostic","Prescriptive","Predictive"],"answer":2,"explain":"<strong>Prescriptive</strong> analytics recommends the optimal decision or action to achieve a desired outcome, the highest maturity level.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Descriptive</b>: descriptive analytics reports what happened, not the best action.</span><span class='qd'><b>Diagnostic</b>: diagnostic analytics explains why something happened, not what to do next.</span><span class='qd'><b>Predictive</b>: predictive analytics forecasts what is likely but stops short of recommending the decision.</span>"},
  {"id":"D3-061","domain":3,"obj":"3.2","diff":"medium","q":"An analyst wants to measure the strength and direction of the linear relationship between advertising spend and revenue without building a predictive equation. Which measure fits BEST?","options":["Regression coefficient","Correlation coefficient","Standard deviation","Confidence interval"],"answer":1,"explain":"<strong>Correlation coefficient</strong> quantifies the strength and direction of a linear relationship between two variables without modeling prediction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Regression coefficient</b>: a regression coefficient is part of a predictive equation, which the analyst explicitly wants to avoid.</span><span class='qd'><b>Standard deviation</b>: standard deviation measures spread of a single variable, not a relationship.</span><span class='qd'><b>Confidence interval</b>: a confidence interval estimates a parameter range, not relationship strength.</span>"},
  {"id":"D3-062","domain":3,"obj":"3.2","diff":"easy","q":"Which statistical category draws conclusions about a whole population based on a sample?","options":["Descriptive statistics","Prescriptive statistics","Inferential statistics","Cosmetic statistics"],"answer":2,"explain":"<strong>Inferential statistics</strong> uses sample data to make generalizations and test hypotheses about a larger population.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Descriptive statistics</b>: descriptive statistics only summarize the data on hand, without generalizing.</span><span class='qd'><b>Prescriptive statistics</b>: 'prescriptive statistics' is not a standard category; prescriptive analytics recommends actions.</span><span class='qd'><b>Cosmetic statistics</b>: this is not a real statistical category.</span>"},
  {"id":"D3-063","domain":3,"obj":"3.2","diff":"hard","q":"An analyst increases the sample size in a study. All else equal, what generally happens to the width of the confidence interval for the mean?","options":["It becomes wider","It becomes narrower","It stays exactly the same","It becomes negative"],"answer":1,"explain":"<strong>It becomes narrower</strong> because a larger sample reduces the standard error, producing a more precise (tighter) confidence interval.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It becomes wider</b>: a wider interval would mean less precision, which is the opposite of adding data.</span><span class='qd'><b>It stays exactly the same</b>: sample size directly affects standard error, so the width changes.</span><span class='qd'><b>It becomes negative</b>: an interval width is a magnitude and cannot be negative.</span>"},
  {"id":"D3-064","domain":3,"obj":"3.2","diff":"medium","q":"An analyst wants to concatenate a customer's first and last name into a single full-name field. Which function category is needed?","options":["Mathematical functions","Date functions","String functions","Logical functions"],"answer":2,"explain":"<strong>String functions</strong> handle text operations including concatenation of name fields.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mathematical functions</b>: math functions perform arithmetic, not text joining.</span><span class='qd'><b>Date functions</b>: date functions manage temporal values, not strings.</span><span class='qd'><b>Logical functions</b>: logical functions evaluate conditions, not concatenate text.</span>"},
  {"id":"D3-065","domain":3,"obj":"3.2","diff":"hard","q":"A symmetric, bell-shaped distribution has mean = median = mode. Approximately what percentage of values fall within one standard deviation of the mean under the empirical rule?","options":["About 68%","About 50%","About 95%","About 99.7%"],"answer":0,"explain":"<strong>About 68%</strong> of values fall within one standard deviation of the mean in a normal distribution under the empirical (68-95-99.7) rule.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>About 50%</b>: 50% corresponds to the median split, not one standard deviation.</span><span class='qd'><b>About 95%</b>: 95% falls within two standard deviations, not one.</span><span class='qd'><b>About 99.7%</b>: 99.7% falls within three standard deviations, not one.</span>"},
  {"id":"D3-066","domain":3,"obj":"3.2","diff":"medium","q":"An analyst computes variance and reports it as 144 (dollars squared). To express the dispersion in dollars, what should the analyst report instead?","options":["The standard deviation, which is 12 dollars","The variance again","The range","The mean"],"answer":0,"explain":"<strong>The standard deviation, which is 12 dollars</strong> is the square root of the variance (sqrt(144) = 12), returning the original units.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The variance again</b>: variance stays in squared units, not the dollars requested.</span><span class='qd'><b>The range</b>: the range is unrelated to variance and uses only the extremes.</span><span class='qd'><b>The mean</b>: the mean is a center measure, not a dispersion measure.</span>"},
  {"id":"D3-067","domain":3,"obj":"3.2","diff":"medium","q":"A team wants to understand why sales dropped last month by drilling into the data to find contributing factors. This is BEST described as which type of analysis?","options":["Prescriptive analysis","Predictive analysis","Diagnostic analysis","Descriptive analysis"],"answer":2,"explain":"<strong>Diagnostic analysis</strong> investigates the causes behind an observed outcome, such as why sales dropped.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Prescriptive analysis</b>: prescriptive analysis recommends actions rather than diagnosing causes.</span><span class='qd'><b>Predictive analysis</b>: predictive analysis forecasts the future, not the reason for a past drop.</span><span class='qd'><b>Descriptive analysis</b>: descriptive analysis reports that sales dropped but does not explain why.</span>"},
  {"id":"D3-068","domain":3,"obj":"3.2","diff":"hard","q":"An analyst performing gap analysis on KPIs compares actual performance to target performance. The 'gap' represents:","options":["The correlation between two variables","The standard deviation of the metric","The difference between the target value and the actual value","The p-value of a test"],"answer":2,"explain":"<strong>The difference between the target value and the actual value</strong> is what a gap analysis measures, highlighting where performance falls short.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The correlation between two variables</b>: correlation measures a relationship, not a target-versus-actual shortfall.</span><span class='qd'><b>The standard deviation of the metric</b>: standard deviation measures spread, not the gap to a goal.</span><span class='qd'><b>The p-value of a test</b>: a p-value relates to significance testing, not gap measurement.</span>"},
  {"id":"D3-069","domain":3,"obj":"3.2","diff":"medium","q":"An analyst must flag rows where the order total exceeds 1000 AND the region equals 'West.' Which function type combines these two conditions?","options":["Date functions","String functions","Aggregate functions","Logical functions (such as AND within an IF)"],"answer":3,"explain":"<strong>Logical functions (such as AND within an IF)</strong> evaluate combined boolean conditions to flag matching rows.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Date functions</b>: date functions handle temporal logic, not multi-condition flagging on totals and regions.</span><span class='qd'><b>String functions</b>: string functions manipulate text but do not evaluate numeric-plus-text conditions.</span><span class='qd'><b>Aggregate functions</b>: aggregates summarize groups, they do not flag individual rows by condition.</span>"},
  {"id":"D3-070","domain":3,"obj":"3.2","diff":"easy","q":"Which measure is MOST affected by a single extreme outlier?","options":["Median","Mean","Mode","Interquartile range"],"answer":1,"explain":"<strong>Mean</strong> is most affected by extreme outliers because every value, including the outlier, enters the sum.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Median</b>: the median depends on the middle position and is resistant to outliers.</span><span class='qd'><b>Mode</b>: the mode reflects the most frequent value and is unaffected by a lone extreme.</span><span class='qd'><b>Interquartile range</b>: the IQR uses the middle 50% and ignores extreme tails.</span>"},
  {"id":"D3-071","domain":3,"obj":"3.2","diff":"hard","q":"An analyst observes a strong correlation between ice cream sales and drowning incidents. What is the MOST appropriate conclusion?","options":["Ice cream causes drowning","A third variable such as hot weather likely drives both; correlation is not causation","Drowning causes ice cream sales","The correlation must be a calculation error"],"answer":1,"explain":"<strong>A third variable such as hot weather likely drives both; correlation is not causation</strong> correctly identifies a confounding variable rather than a causal link.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ice cream causes drowning</b>: this assumes causation from correlation, a classic error.</span><span class='qd'><b>Drowning causes ice cream sales</b>: this reverses an implausible causal claim and is equally unfounded.</span><span class='qd'><b>The correlation must be a calculation error</b>: a real correlation can exist due to a confounder; it is not necessarily an error.</span>"},
  {"id":"D3-072","domain":3,"obj":"3.2","diff":"medium","q":"An analyst needs to convert a stored datetime to just the year so records can be grouped annually. Which function category accomplishes this?","options":["Date functions (such as YEAR)","String functions","Logical functions","Math functions"],"answer":0,"explain":"<strong>Date functions (such as YEAR)</strong> extract date components like the year from a datetime value.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>String functions</b>: while you could parse text, the value is a datetime, so a date function is the proper tool.</span><span class='qd'><b>Logical functions</b>: logical functions test conditions, not extract date parts.</span><span class='qd'><b>Math functions</b>: math functions handle arithmetic, not calendar components.</span>"},
  {"id":"D3-073","domain":3,"obj":"3.2","diff":"hard","q":"A dataset has values 2, 4, 4, 4, 5, 5, 7, 9. Which statement is correct?","options":["The mode is 5","The mean is greater than 9","The mode is 4 and the median is 4.5","There is no mode"],"answer":2,"explain":"<strong>The mode is 4 and the median is 4.5</strong>: 4 occurs three times (the mode), and the two middle values (4 and 5) average to 4.5 (the median).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The mode is 5</b>: 5 appears twice while 4 appears three times, so 4 is the mode.</span><span class='qd'><b>The mean is greater than 9</b>: the sum is 40 over 8 values, giving a mean of 5, far below 9.</span><span class='qd'><b>There is no mode</b>: 4 repeats most often, so a mode clearly exists.</span>"},
  {"id":"D3-074","domain":3,"obj":"3.2","diff":"medium","q":"A company sets alpha at 0.01 instead of 0.05 for a critical safety test. What is the practical effect of choosing the smaller alpha?","options":["It makes false positives more likely","It guarantees the result is correct","It eliminates the need for a p-value","It requires stronger evidence to reject the null, reducing the chance of a Type I error"],"answer":3,"explain":"<strong>It requires stronger evidence to reject the null, reducing the chance of a Type I error</strong> because a smaller alpha sets a stricter significance threshold.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes false positives more likely</b>: a smaller alpha lowers, not raises, the false-positive rate.</span><span class='qd'><b>It guarantees the result is correct</b>: no alpha guarantees correctness; it manages error probability.</span><span class='qd'><b>It eliminates the need for a p-value</b>: alpha is compared against the p-value, which is still required.</span>"},
  {"id":"D3-075","domain":3,"obj":"3.2","diff":"easy","q":"Which of the following is a measure of dispersion rather than central tendency?","options":["Mean","Median","Mode","Variance"],"answer":3,"explain":"<strong>Variance</strong> measures how spread out values are around the mean, making it a measure of dispersion.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mean</b>: the mean is a measure of central tendency.</span><span class='qd'><b>Median</b>: the median is a measure of central tendency.</span><span class='qd'><b>Mode</b>: the mode is a measure of central tendency.</span>"},
  {"id":"D3-076","domain":3,"obj":"3.2","diff":"hard","q":"An analyst must choose between reporting the mean or the median for employee salaries to give a fair sense of typical pay, knowing a few executives earn far more than everyone else. What is the BEST choice and why?","options":["Mean, because it uses all the data points","Median, because it resists distortion from the few very high executive salaries","Mode, because it is the most common salary","Range, because it shows the highest and lowest pay"],"answer":1,"explain":"<strong>Median, because it resists distortion from the few very high executive salaries</strong> gives a fairer sense of typical pay in a right-skewed salary distribution.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mean, because it uses all the data points</b>: using all points lets the executive outliers inflate the figure, misrepresenting typical pay.</span><span class='qd'><b>Mode, because it is the most common salary</b>: the most common salary may not reflect the center of the distribution.</span><span class='qd'><b>Range, because it shows the highest and lowest pay</b>: the range describes spread, not the typical value.</span>"},
  {"id":"D3-077","domain":3,"obj":"3.2","diff":"medium","q":"An analyst wants to round a calculated average to two decimal places before displaying it. Which function category provides ROUND?","options":["Mathematical functions","Date functions","String functions","Logical functions"],"answer":0,"explain":"<strong>Mathematical functions</strong> include ROUND, which adjusts numeric precision to a specified number of decimals.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Date functions</b>: date functions handle calendar values, not numeric rounding.</span><span class='qd'><b>String functions</b>: string functions format text and do not perform numeric rounding logic.</span><span class='qd'><b>Logical functions</b>: logical functions evaluate conditions, not rounding.</span>"},
  {"id":"D3-078","domain":3,"obj":"3.2","diff":"hard","q":"An A/B test shows version B has a higher conversion rate, with a p-value of 0.04 and a 95% confidence interval for the difference of [0.5%, 3.0%]. What is the soundest interpretation?","options":["The difference is not significant because the interval includes zero","The difference is statistically significant and the interval excludes zero, supporting a real positive effect","The result proves B is better for every future user","The p-value means there is a 4% chance B is worse"],"answer":1,"explain":"<strong>The difference is statistically significant and the interval excludes zero, supporting a real positive effect</strong> because p < 0.05 and the entire CI is above zero.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The difference is not significant because the interval includes zero</b>: the interval [0.5%, 3.0%] does not include zero, so this premise is false.</span><span class='qd'><b>The result proves B is better for every future user</b>: statistics support a population effect on average, not a guarantee for every individual.</span><span class='qd'><b>The p-value means there is a 4% chance B is worse</b>: the p-value is the probability of the data under the null, not the probability B is worse.</span>"},
  {"id":"D3-079","domain":3,"obj":"3.2","diff":"medium","q":"A data scientist describes their work as 'using statistical models and machine learning to forecast equipment failures before they occur.' Which analysis type is this?","options":["Descriptive","Predictive","Prescriptive","Diagnostic"],"answer":1,"explain":"<strong>Predictive</strong> analysis forecasts future events such as equipment failures using statistical and machine-learning models.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Descriptive</b>: descriptive analysis summarizes past failures, it does not forecast new ones.</span><span class='qd'><b>Prescriptive</b>: prescriptive analysis recommends maintenance actions, a step beyond forecasting.</span><span class='qd'><b>Diagnostic</b>: diagnostic analysis explains why a past failure happened, not when the next one will occur.</span>"},
  {"id":"D3-080","domain":3,"obj":"3.2","diff":"hard","q":"An analyst sees that variance for Dataset X is 0. What can be concluded?","options":["All values in the dataset are identical","The data has a wide spread","The mean cannot be computed","The dataset has many outliers"],"answer":0,"explain":"<strong>All values in the dataset are identical</strong> because variance of zero means no deviation from the mean exists.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data has a wide spread</b>: wide spread implies large variance, the opposite of zero.</span><span class='qd'><b>The mean cannot be computed</b>: the mean is computable; with identical values it equals that value.</span><span class='qd'><b>The dataset has many outliers</b>: outliers create variance, so zero variance means none exist.</span>"},
  {"id":"D3-081","domain":3,"obj":"3.3","diff":"easy","q":"An analyst's query suddenly returns 'cannot connect to server.' What is the FIRST thing to check?","options":["The database connectivity, such as credentials, network access, and whether the server is up","The chart color scheme","The spelling of the report title","The font size in the dashboard"],"answer":0,"explain":"<strong>The database connectivity, such as credentials, network access, and whether the server is up</strong> directly addresses a connection error before anything else.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The chart color scheme</b>: styling cannot cause or fix a server connection failure.</span><span class='qd'><b>The spelling of the report title</b>: a title typo is unrelated to connectivity.</span><span class='qd'><b>The font size in the dashboard</b>: fonts have no bearing on database access.</span>"},
  {"id":"D3-082","domain":3,"obj":"3.3","diff":"medium","q":"A user reports that a report shows the wrong total, but the analyst sees correct numbers in their own session. What is the BEST first troubleshooting step?","options":["Rewrite the entire report from scratch","Tell the user the report is correct","Delete the report","Reproduce the issue using the same filters, parameters, and access the user has"],"answer":3,"explain":"<strong>Reproduce the issue using the same filters, parameters, and access the user has</strong> is the correct way to investigate a user-reported discrepancy you cannot see yourself.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Rewrite the entire report from scratch</b>: rewriting before understanding the cause is wasteful and may not fix anything.</span><span class='qd'><b>Tell the user the report is correct</b>: dismissing the report without reproducing the user's exact conditions ignores possible filter or permission differences.</span><span class='qd'><b>Delete the report</b>: deletion destroys the artifact instead of diagnosing the problem.</span>"},
  {"id":"D3-083","domain":3,"obj":"3.3","diff":"medium","q":"A SQL query returns no rows when the analyst expected results. Which is the MOST likely basic SQL issue to check first?","options":["The monitor's brightness","The keyboard layout","The operating system version","A WHERE clause filter that is too restrictive or mistyped"],"answer":3,"explain":"<strong>A WHERE clause filter that is too restrictive or mistyped</strong> is a common reason a query unexpectedly returns zero rows.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The monitor's brightness</b>: display settings cannot affect query results.</span><span class='qd'><b>The keyboard layout</b>: keyboard layout does not change SQL logic.</span><span class='qd'><b>The operating system version</b>: the OS version is unrelated to a filter returning no rows.</span>"},
  {"id":"D3-084","domain":3,"obj":"3.3","diff":"hard","q":"An analyst's join unexpectedly produces far more rows than either source table. Which SQL issue is the MOST likely cause?","options":["A missing ORDER BY clause","A join condition that is missing or incorrect, causing a Cartesian or many-to-many explosion","Using SELECT * instead of named columns","A comment in the wrong place"],"answer":1,"explain":"<strong>A join condition that is missing or incorrect, causing a Cartesian or many-to-many explosion</strong> is the classic cause of row counts ballooning beyond either table.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A missing ORDER BY clause</b>: ORDER BY only sorts rows; it never increases their count.</span><span class='qd'><b>Using SELECT * instead of named columns</b>: SELECT * affects which columns return, not the number of rows.</span><span class='qd'><b>A comment in the wrong place</b>: a misplaced comment usually errors out rather than multiplying rows.</span>"},
  {"id":"D3-085","domain":3,"obj":"3.3","diff":"medium","q":"An analyst suspects a CSV import produced garbled characters and shifted columns. What does this MOST likely indicate?","options":["A perfect import","A faster query","A new KPI","A corrupted or improperly encoded/delimited data file"],"answer":3,"explain":"<strong>A corrupted or improperly encoded/delimited data file</strong> explains garbled characters and misaligned columns after import.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A perfect import</b>: garbled, shifted data is the opposite of a clean import.</span><span class='qd'><b>A faster query</b>: corruption does not relate to query speed.</span><span class='qd'><b>A new KPI</b>: a KPI is a metric, not a file-corruption symptom.</span>"},
  {"id":"D3-086","domain":3,"obj":"3.3","diff":"hard","q":"While troubleshooting an intermittent failure in a data pipeline, an analyst cannot see what step is failing. Which action BEST improves visibility into the root cause?","options":["Lower the screen resolution","Enable detailed logging so each step's status and errors are recorded","Change the dashboard theme","Increase the font size of the error message"],"answer":1,"explain":"<strong>Enable detailed logging so each step's status and errors are recorded</strong> provides the diagnostic trail needed to locate an intermittent failure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Lower the screen resolution</b>: resolution has no effect on diagnosing pipeline failures.</span><span class='qd'><b>Change the dashboard theme</b>: theming is cosmetic and reveals nothing about errors.</span><span class='qd'><b>Increase the font size of the error message</b>: larger text does not produce more diagnostic information.</span>"},
  {"id":"D3-087","domain":3,"obj":"3.3","diff":"medium","q":"A dashboard's numbers look wrong, and the analyst suspects the underlying source changed. Which action BEST verifies this?","options":["Change the chart type","Validate the data against the original source system to confirm accuracy","Add more colors to the dashboard","Email the report to more people"],"answer":1,"explain":"<strong>Validate the data against the original source system to confirm accuracy</strong> directly tests whether the source has drifted from the report.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Change the chart type</b>: changing visuals does not verify data accuracy.</span><span class='qd'><b>Add more colors to the dashboard</b>: styling cannot confirm whether numbers are correct.</span><span class='qd'><b>Email the report to more people</b>: wider distribution spreads the suspect numbers rather than validating them.</span>"},
  {"id":"D3-088","domain":3,"obj":"3.3","diff":"hard","q":"An analyst is stuck on a cryptic error from a specialized BI tool that internal staff have never seen. What is the MOST appropriate next resource?","options":["Ignore the error and ship the report","Consult the vendor's documentation, knowledge base, or community forums for that tool","Reformat the analyst's hard drive","Switch careers"],"answer":1,"explain":"<strong>Consult the vendor's documentation, knowledge base, or community forums for that tool</strong> leverages vendor resources designed to resolve product-specific errors.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore the error and ship the report</b>: shipping a known-broken report risks delivering wrong results.</span><span class='qd'><b>Reformat the analyst's hard drive</b>: a drastic, unrelated action that does not address a tool-specific error.</span><span class='qd'><b>Switch careers</b>: this is not a troubleshooting step.</span>"},
  {"id":"D3-089","domain":3,"obj":"3.3","diff":"easy","q":"A user says a report 'won't load at all.' Which is the BEST clarifying question to begin troubleshooting?","options":["What color do you want the title?","Do you like the font?","What exact error message appears, and can others access the same report?","Which charts are your favorite?"],"answer":2,"explain":"<strong>What exact error message appears, and can others access the same report?</strong> gathers the symptom detail and scope needed to isolate the cause.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>What color do you want the title?</b>: title color is irrelevant to a loading failure.</span><span class='qd'><b>Do you like the font?</b>: font preference does not diagnose why the report fails to load.</span><span class='qd'><b>Which charts are your favorite?</b>: chart preferences provide no troubleshooting information.</span>"},
  {"id":"D3-090","domain":3,"obj":"3.3","diff":"medium","q":"An analyst's scheduled query worked yesterday but fails today with an authentication error. What is the MOST likely cause to investigate FIRST?","options":["The query logic changed by itself","The chart legend moved","Expired or rotated credentials, or a revoked service account","The report title font"],"answer":2,"explain":"<strong>Expired or rotated credentials, or a revoked service account</strong> is the most likely reason a previously working job now returns an authentication error.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The query logic changed by itself</b>: code does not change on its own without an edit or deployment.</span><span class='qd'><b>The chart legend moved</b>: a legend position cannot trigger an authentication failure.</span><span class='qd'><b>The report title font</b>: fonts have no role in authentication.</span>"},
  {"id":"D3-091","domain":3,"obj":"3.3","diff":"hard","q":"After importing data, an analyst notices some numeric totals are far larger than possible because a few cells contain text concatenated with numbers. What is the BEST troubleshooting conclusion?","options":["The data is fine and should be published","The query needs more colors","The report should be deleted","The source data is corrupted or malformed and must be validated and cleansed before analysis"],"answer":3,"explain":"<strong>The source data is corrupted or malformed and must be validated and cleansed before analysis</strong> addresses the malformed values producing impossible totals.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data is fine and should be published</b>: publishing impossible totals propagates corrupt data.</span><span class='qd'><b>The query needs more colors</b>: styling does not fix malformed source values.</span><span class='qd'><b>The report should be deleted</b>: the issue is the data, which can be cleansed rather than discarding the report.</span>"},
  {"id":"D3-092","domain":3,"obj":"3.3","diff":"medium","q":"Multiple users report the same dashboard is broken, but one specific user has no issue. What does this pattern MOST suggest?","options":["The dashboard is entirely fine","The problem is the monitor brand","The data warehouse was deleted","A difference tied to that one user's permissions, filters, cache, or browser is masking a broader problem"],"answer":3,"explain":"<strong>A difference tied to that one user's permissions, filters, cache, or browser is masking a broader problem</strong> explains why most users fail while one does not.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The dashboard is entirely fine</b>: multiple failure reports indicate a real problem.</span><span class='qd'><b>The problem is the monitor brand</b>: monitor hardware does not cause a shared dashboard failure.</span><span class='qd'><b>The data warehouse was deleted</b>: if the warehouse were gone, the one working user would also fail.</span>"},
  {"id":"D3-093","domain":3,"obj":"3.3","diff":"hard","q":"An analyst finds that enabling query logging shows the report runs a stored procedure that references a table renamed during a recent migration. What is the root cause?","options":["The dashboard color theme","The user's keyboard","A broken reference to a renamed/removed object after a schema change","An outdated font package"],"answer":2,"explain":"<strong>A broken reference to a renamed/removed object after a schema change</strong> is the root cause revealed by the log: the procedure points to an object that no longer exists by that name.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The dashboard color theme</b>: theming cannot break a stored procedure's object reference.</span><span class='qd'><b>The user's keyboard</b>: keyboards do not affect server-side object references.</span><span class='qd'><b>An outdated font package</b>: fonts are unrelated to database schema references.</span>"},
  {"id":"D3-094","domain":3,"obj":"3.3","diff":"easy","q":"Why is reviewing application or query logs valuable when troubleshooting an analysis failure?","options":["Logs record errors, timestamps, and the sequence of events that pinpoint where the failure occurred","Logs change the chart colors","Logs make queries run faster automatically","Logs replace the need for data validation"],"answer":0,"explain":"<strong>Logs record errors, timestamps, and the sequence of events that pinpoint where the failure occurred</strong>, making them essential for diagnosis.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Logs change the chart colors</b>: logs record events; they do not alter visuals.</span><span class='qd'><b>Logs make queries run faster automatically</b>: logging records activity and may even add slight overhead, not speed.</span><span class='qd'><b>Logs replace the need for data validation</b>: logs aid diagnosis but do not replace validating the data itself.</span>"},
  {"id":"D3-095","domain":3,"obj":"3.3","diff":"medium","q":"A query intermittently times out only during business hours. Which explanation is MOST consistent with this pattern?","options":["The SQL syntax is invalid","The report title is misspelled","The user is colorblind","Resource contention or heavy concurrent load on the database during peak hours"],"answer":3,"explain":"<strong>Resource contention or heavy concurrent load on the database during peak hours</strong> explains timeouts that occur only when usage is high.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The SQL syntax is invalid</b>: a syntax error would fail every time, not only during business hours.</span><span class='qd'><b>The report title is misspelled</b>: a title typo cannot cause time-based timeouts.</span><span class='qd'><b>The user is colorblind</b>: accessibility needs have nothing to do with query timeouts.</span>"},
  {"id":"D3-096","domain":3,"obj":"3.3","diff":"hard","q":"An analyst receives conflicting numbers from two reports that should match. What is the BEST methodical troubleshooting approach?","options":["Pick the number that looks better","Average the two numbers and move on","Assume both are wrong and delete them","Trace each report back to its data source, compare queries, filters, and refresh times to find where they diverge"],"answer":3,"explain":"<strong>Trace each report back to its data source, compare queries, filters, and refresh times to find where they diverge</strong> is a systematic root-cause approach to reconcile conflicting figures.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pick the number that looks better</b>: choosing by appearance ignores which figure is actually correct.</span><span class='qd'><b>Average the two numbers and move on</b>: averaging two figures does not resolve why they differ and may produce a wrong value.</span><span class='qd'><b>Assume both are wrong and delete them</b>: deletion abandons diagnosis and loses potentially correct work.</span>"},
  {"id":"D3-097","domain":3,"obj":"3.3","diff":"medium","q":"A user-reported issue cannot be reproduced. Before closing it, what is the BEST practice?","options":["Gather more detail (screenshots, steps, exact time, user account) and check logs around that time to confirm whether it occurred","Close it immediately as not-a-bug","Blame the user","Restart every server in the company"],"answer":0,"explain":"<strong>Gather more detail (screenshots, steps, exact time, user account) and check logs around that time to confirm whether it occurred</strong> ensures the issue is properly investigated before closing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Close it immediately as not-a-bug</b>: closing without investigation may dismiss a real intermittent problem.</span><span class='qd'><b>Blame the user</b>: blaming is unprofessional and skips diagnosis.</span><span class='qd'><b>Restart every server in the company</b>: a sweeping restart is disruptive and not a targeted diagnostic step.</span>"},
  {"id":"D3-098","domain":3,"obj":"3.3","diff":"hard","q":"An analyst's results changed after a vendor pushed a software update to the BI platform. What is the MOST appropriate first response?","options":["Conclude the data is permanently broken","Check the vendor's release notes and known-issues/community resources to see if the update changed behavior, then validate results","Delete the BI platform","Ignore it because vendors are always right"],"answer":1,"explain":"<strong>Check the vendor's release notes and known-issues/community resources to see if the update changed behavior, then validate results</strong> uses vendor resources to explain post-update changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Conclude the data is permanently broken</b>: an update changing behavior is often documented and fixable, not permanent breakage.</span><span class='qd'><b>Delete the BI platform</b>: removing the tool is drastic and skips diagnosis.</span><span class='qd'><b>Ignore it because vendors are always right</b>: ignoring a behavior change can leave incorrect results in production.</span>"},
  {"id":"D3-099","domain":3,"obj":"3.3","diff":"medium","q":"An analyst writes SELECT customer, SUM(amount) FROM orders but the query errors out. Which basic SQL fix is MOST likely required?","options":["Change the database server","Add more colors to the output","Add a GROUP BY customer clause because a non-aggregated column is selected with an aggregate","Rename the table"],"answer":2,"explain":"<strong>Add a GROUP BY customer clause because a non-aggregated column is selected with an aggregate</strong> resolves the error of mixing a column with SUM without grouping.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Change the database server</b>: the error is a query-logic problem, not a server problem.</span><span class='qd'><b>Add more colors to the output</b>: output styling cannot fix a SQL grouping error.</span><span class='qd'><b>Rename the table</b>: the table name is not the source of the aggregation error.</span>"},
  {"id":"D3-100","domain":3,"obj":"3.3","diff":"hard","q":"After validating connectivity, credentials, and SQL logic, an analyst still gets inconsistent results and suspects the source feed itself. What is the BEST final validation step?","options":["Change the dashboard's font","Compare the loaded data row counts and key totals against the authoritative source system of record","Reduce the number of charts","Email the vendor a thank-you note"],"answer":1,"explain":"<strong>Compare the loaded data row counts and key totals against the authoritative source system of record</strong> validates the source feed to confirm whether ingestion matches the system of record.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Change the dashboard's font</b>: fonts do not validate data integrity.</span><span class='qd'><b>Reduce the number of charts</b>: chart count is unrelated to verifying source accuracy.</span><span class='qd'><b>Email the vendor a thank-you note</b>: courtesy does not validate the data feed.</span>"}
);
